SELECT ror.* FROM t_receive_order_verification ror
where receive_order_id in

    #{item}

SELECT
rov.*
FROM t_receive_order_verification rov
left join t_receive_order ro on ro.receive_order_id = rov.receive_order_id


        and rov.enterprise_id = #{queryForm.enterpriseId}


        and DATE_FORMAT(rov.verification_time, '%Y-%m-%d') >= #{queryForm.verificationStartTime}


        and DATE_FORMAT(rov.verification_time, '%Y-%m-%d') <= #{queryForm.verificationEndTime}


        and DATE_FORMAT(rov.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(rov.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and ro.check_status != #{queryForm.receiveOrderExcludeCheckStatus}

SELECT IFNULL(SUM(rov.verification_amount),0)
FROM t_receive_order_verification rov
left join t_receive_order ro on ro.receive_order_id = rov.receive_order_id


        and rov.enterprise_id = #{queryForm.enterpriseId}


        and DATE_FORMAT(rov.verification_time, '%Y-%m-%d') >= #{queryForm.verificationStartTime}


        and DATE_FORMAT(rov.verification_time, '%Y-%m-%d') <= #{queryForm.verificationEndTime}


        and DATE_FORMAT(rov.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(rov.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and ro.check_status != #{queryForm.receiveOrderExcludeCheckStatus}

SELECT SUM(verification_amount) verificationTotalAmount FROM t_receive_order_verification
WHERE receive_order_id IN

    #{item}

SELECT receive_order_id, IFNULL(SUM(verification_amount), 0) verificationAmount FROM t_receive_order_verification WHERE receive_order_id IN
#{item}
GROUP BY receive_order_id
